using Employee.Application.Common.Events;\nusing Employee.Application.Common.Messaging;\nusing Employee.Infrastructure.Messaging.Outbox;\nusing Microsoft.Extensions.Hosting;\n\nnamespace Employee.Infrastructure.Messaging\n{\n    /// <summary>\n    /// Background service for processing undelivered outbox messages\n    /// Retries publishing events that failed\n    /// </summary>\n    public class OutboxPublisherBackgroundService : BackgroundService\n    {\n        private readonly IServiceProvider _serviceProvider;\n        private readonly ILogger<OutboxPublisherBackgroundService> _logger;\n        private readonly TimeSpan _delay = TimeSpan.FromSeconds(30);\n        private const int MaxRetries = 5;\n\n        public OutboxPublisherBackgroundService(\n            IServiceProvider serviceProvider,\n            ILogger<OutboxPublisherBackgroundService> logger)\n        {\n            _serviceProvider = serviceProvider;\n            _logger = logger;\n        }\n\n        protected override async Task ExecuteAsync(CancellationToken stoppingToken)\n        {\n            _logger.LogInformation(\"Outbox Publisher Background Service started\");\n\n            while (!stoppingToken.IsCancellationRequested)\n            {\n                try\n                {\n                    using (var scope = _serviceProvider.CreateScope())\n                    {\n                        var outboxRepository = scope.ServiceProvider.GetRequiredService<IOutboxRepository>();\n                        var eventPublisher = scope.ServiceProvider.GetRequiredService<IEventPublisher>();\n\n                        var unprocessedMessages = await outboxRepository.GetUnprocessedAsync(stoppingToken);\n\n                        foreach (var message in unprocessedMessages)\n                        {\n                            try\n                            {\n                                _logger.LogInformation(\n                                    \"Retrying outbox message: {MessageId}, EventType: {EventType}, RetryCount: {RetryCount}\",\n                                    message.Id,\n                                    message.EventType,\n                                    message.RetryCount);\n\n                                // Parse and republish the event\n                                // This is a simplified approach; implement deserialization based on EventType\n                                // TODO: Implement proper event deserialization factory\n\n                                message.IsProcessed = true;\n                                message.ProcessedAt = DateTime.UtcNow;\n                                await outboxRepository.UpdateAsync(message, stoppingToken);\n\n                                _logger.LogInformation(\"Outbox message processed successfully: {MessageId}\", message.Id);\n                            }\n                            catch (Exception ex)\n                            {\n                                message.RetryCount++;\n                                message.Error = ex.Message;\n\n                                if (message.RetryCount >= MaxRetries)\n                                {\n                                    message.IsProcessed = true;\n                                    _logger.LogError(\n                                        \"Outbox message max retries exceeded: {MessageId}, Error: {Error}\",\n                                        message.Id,\n                                        ex.Message);\n                                }\n\n                                await outboxRepository.UpdateAsync(message, stoppingToken);\n                            }\n                        }\n                    }\n                }\n                catch (Exception ex)\n                {\n                    _logger.LogError(ex, \"Error in Outbox Publisher Background Service\");\n                }\n\n                await Task.Delay(_delay, stoppingToken);\n            }\n\n            _logger.LogInformation(\"Outbox Publisher Background Service stopped\");\n        }\n    }\n}\n